import { createSlice } from "@reduxjs/toolkit"
import _ from "lodash"
import preset from "../datasheet/screen_preset.yml"

export const displaySlice = createSlice({
  name: "display",
  initialState: {
    name: "screen",
    width: 1920,
    height: 1080,
    aspect: {
      w: 16,
      h: 9,
      lock: true,
    },
    size: 24,
    curvature: {
      use: false,
      r: 1500,
    },
    deviceList: [
      {
        name: "Philips 32'",
        slot: 0,
        width: 2560,
        height: 1440,
        aspect: {
          w: 16,
          h: 9,
          lock: true,
        },
        size: 32,
        curvature: {
          use: true,
          r: 1500,
        },
        // curvature: 1500,
      },
    ],
  },
  reducers: {
    setName: (state, action) => {
      state.name = action.payload
    },
    setWidth: (state, action) => {
      state.width = Number(action.payload)
      if (state.aspect.lock) {
        state.height = Math.round(
          Number((action.payload * state.aspect.h) / state.aspect.w)
        )
      }
    },
    setHeight: (state, action) => {
      state.height = Number(action.payload)
      if (state.aspect.lock) {
        state.width = Math.round(
          Number((action.payload * state.aspect.w) / state.aspect.h)
        )
      }
    },
    setSize: (state, action) => {
      const newSize = Number(action.payload || 0)
      state.size = newSize >= 0 ? newSize : 0
    },
    setAspect: (state, action) => {
      switch (action.payload.type) {
        case "w":
          state.width = Number(
            (state.width / state.aspect.w) * action.payload.ratio
          ).toFixed(0)
          state.aspect.w = action.payload.ratio
          return
        case "h":
          state.height = Number(
            (state.height / state.aspect.h) * action.payload.ratio
          ).toFixed(0)
          state.aspect.h = action.payload.ratio
          return
        default:
          return
      }
    },
    setCurvature: (state, action) => {
      state.curvature.r = Number(action.payload || 0)
    },
    setUseCurvature: (state, action) => {
      state.curvature.use = action.payload || false
    },
    saveDevice: state => {
      const { deviceList, ...current } = state
      const last = _.findLastIndex(deviceList, { name: current.name })
      if (last !== -1) {
        current.slot = deviceList[last].slot + 1
      } else {
        current.slot = 0
      }
      state.deviceList.push(current)
    },
    deleteDevice: (state, action) => {
      const { deviceList } = state
      const last = _.findIndex(deviceList, {
        name: action.payload?.name,
        slot: action.payload?.slot,
      })
      if (last !== -1) {
        state.deviceList.splice(last, 1)
      }
    },
    loadDevice: (state, action) => {
      const { deviceList } = state
      const last = _.findLastIndex(deviceList, {
        name: action.payload?.name,
        slot: action.payload?.slot,
      })
      if (last !== -1) {
        const { slot, ...data } = deviceList[last]
        Object.assign(state, data)
        // state.width=data.width
        // state.height=data.height
        // state.aspect.h = data.aspect.h
        // state.aspect.w = data.aspect.w
        // state.size = data.size
      }
    },
    loadPreset: (state, action) => {
      if (action?.payload?.name) {
        const data = _.find(preset, { name: String(action.payload.name) })
        Object.assign(state, data)
      }
    },
    loadFullState: (state, action) => {
      if (action?.payload) {
        // DANGEROUS
        Object.assign(state, action.payload)
      }
    },
  },
})

export const {
  setWidth,
  setHeight,
  setSize,
  saveDevice,
  deleteDevice,
  loadDevice,
  setName,
  setCurvature,
  setUseCurvature,
  setAspect,
  loadPreset,
  loadFullState,
} = displaySlice.actions

// The function below is called a thunk and allows us to perform async logic. It
// can be dispatched like a regular action: `dispatch(incrementAsync(10))`. This
// will call the thunk with the `dispatch` function as the first argument. Async
// code can then be executed and other actions can be dispatched

export const selectWidth = state => state.display.width
export const selectHeight = state => state.display.height

export default displaySlice.reducer
